GET /orders/42 HTTP/1.1
Host: api.example.com

HTTP/1.1 200 OK
Content-Type: application/hal+json

{
  "id": 42,
  "status": "pending",
  "total": 129.99,
  "_links": {
    "self":   { "href": "/orders/42" },
    "pay":    { "href": "/orders/42/payments", "method": "POST" },
    "cancel": { "href": "/orders/42/cancel",   "method": "DELETE" },
    "items":  { "href": "/orders/42/items" }
  }
}

# users-subgraph — owns User entity
type User @key(fields: "id") {
  id: ID!
  name: String!
  email: String!
}

# orders-subgraph — extends User with order data
type User @key(fields: "id") @extends {
  id: ID! @external
  orders: [Order!]!
}

type Order {
  id: ID!
  total: Float!
  status: String!
}

# Step 1: Client registers query at build time
# Hash: sha256("query GetUser($id: ID!) { user(id: $id) { name email } }")
# = "a1b2c3d4e5f6..."

# Step 2: Runtime request (only the hash travels)
POST /graphql
{
  "extensions": {
    "persistedQuery": {
      "version": 1,
      "sha256Hash": "a1b2c3d4e5f6..."
    }
  },
  "variables": { "id": "42" }
}

# First page
GET /events?limit=20

{
  "data": [ { "id": 1001, ... }, ... ],
  "pagination": {
    "next_cursor": "eyJpZCI6MTAyMH0=",
    "has_more": true
  }
}

# Fetch next page using cursor
GET /events?limit=20&cursor=eyJpZCI6MTAyMH0=

# Translates server-side to:
# SELECT * FROM events WHERE id < 1020 ORDER BY id DESC LIMIT 20

GET /analysis/stream HTTP/1.1
Accept: text/event-stream

