data: {"type":"done","total_findings":2}

// Tool definition passed to the model
{
  "name": "get_order_status",
  "description": "Fetch real-time order status from the database.",
  "input_schema": {
    "type": "object",
    "properties": {
      "order_id": { "type": "string", "description": "Order UUID" }
    },
    "required": ["order_id"]
  }
}

// Model emits (instead of prose):
{
  "type": "tool_use",
  "name": "get_order_status",
  "input": { "order_id": "ord_abc123" }
}

// Host executes, returns result to model:
{ "type": "tool_result", "content": "status: shipped, eta: 2025-11-17" }

// MCP server capability advertisement (JSON-RPC 2.0)
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "capabilities": {
      "tools": {},
      "resources": { "subscribe": true },
      "prompts": {}
    },
    "serverInfo": {
      "name": "analytics-mcp-server",
      "version": "1.2.0"
    }
  }
}

// Tool call from host to MCP server
{
  "jsonrpc": "2.0",
  "id": 2,
  "method": "tools/call",
  "params": {
    "name": "run_report",
    "arguments": { "report_id": "weekly-revenue", "period": "2025-W44" }
  }
}

// Agent-first endpoint response — structured, context-rich
// POST /tasks
{
  "task_id": "tsk_abc123",
  "status": "created",
  "idempotency_key": "idem_xyz789",
  "available_actions": [
    { "action": "assign",   "endpoint": "POST /tasks/tsk_abc123/assignee" },
    { "action": "complete", "endpoint": "POST /tasks/tsk_abc123/complete" },
    { "action": "cancel",   "endpoint": "DELETE /tasks/tsk_abc123" }
  ],
  "constraints": {
    "can_delete": false,
    "reason": "task has dependents"
  }
}

// Agent session token — narrow scopes, short TTL
{
  "access_token": "agt_tok_eyJ...",
  "token_type": "Bearer",
  "expires_in": 900,
  "scope": "github:read jira:issues:write slack:messages:read",
  "agent_session_id": "sess_abc123",
  "principal": "user:sivsadha@example.com",
  "issued_at": "2025-11-15T14:00:00Z",
  "revocation_endpoint": "https://auth.example.com/revoke"
}

// Audit log entry for every agent-initiated call:
{
  "ts": "2025-11-15T14:03:22Z",
